#include <torch/extension.h>
#include <cuda_runtime.h>

// GELU tanh-approximation: 0.5 * x * (1 + tanh(sqrt(2/pi) * (x + 0.044715 * x^3)))
// Fused element-wise: 1 read + 1 write = 8 B/elem vs 84 B/elem for the 9-op reference.
//
// Memory-bound (AI=3 << 9.74 ridge): HBM bandwidth is the ceiling.
// Levers: float4 vectorized LDG.E.128 / STG.E.128 (128-bit transactions),
// persistent grid-stride (fills 148 SMs), 8-way warp coarsening (8 elements/thread),
// tanhf() intrinsic (same SFU path as torch.tanh, bit-exact).

__global__ void gelu_tanh_kernel(
    const float* __restrict__ x,
    float* __restrict__ out,
    size_t n
) {
    // Each thread processes 8 elements per iteration = 2 x float4 loads/stores.
    constexpr int ELEMS_PER_THREAD = 8;
    constexpr float SQRT_2_OVER_PI = 0.7978845608028654f;
    constexpr float COEFF = 0.044715f;

    size_t tid = blockIdx.x * blockDim.x + threadIdx.x;
    size_t stride = gridDim.x * blockDim.x * ELEMS_PER_THREAD;

    for (size_t i = tid * ELEMS_PER_THREAD; i < n; i += stride) {
        int rem = static_cast<int>(n - i);

        if (rem >= 8) {
            // Full vectorized path: 2 x float4 (128-bit each), coalesced.
            const float4* x4 = reinterpret_cast<const float4*>(x + i);
            float4* o4 = reinterpret_cast<float4*>(out + i);

            float4 v0 = x4[0];
            float4 v1 = x4[1];

            float a0 = v0.x, a1 = v0.y, a2 = v0.z, a3 = v0.w;
            float b0 = v1.x, b1 = v1.y, b2 = v1.z, b3 = v1.w;

            // Unrolled GELU tanh: 8 independent computations to maximize ILP.
            // Each: v3 = v^3, inner = sqrt(2/pi) * (v + 0.044715 * v3),
            //       t = tanhf(inner), result = 0.5 * v * (1 + t)
            float v, v3, inner, t;

            v = a0; v3 = v * v * v;
            inner = SQRT_2_OVER_PI * (v + COEFF * v3);
            t = tanhf(inner); a0 = 0.5f * v * (1.0f + t);

            v = a1; v3 = v * v * v;
            inner = SQRT_2_OVER_PI * (v + COEFF * v3);
            t = tanhf(inner); a1 = 0.5f * v * (1.0f + t);

            v = a2; v3 = v * v * v;
            inner = SQRT_2_OVER_PI * (v + COEFF * v3);
            t = tanhf(inner); a2 = 0.5f * v * (1.0f + t);

            v = a3; v3 = v * v * v;
            inner = SQRT_2_OVER_PI * (v + COEFF * v3);
            t = tanhf(inner); a3 = 0.5f * v * (1.0f + t);

            v = b0; v3 = v * v * v;
            inner = SQRT_2_OVER_PI * (v + COEFF * v3);
            t = tanhf(inner); b0 = 0.5f * v * (1.0f + t);

            v = b1; v3 = v * v * v;
            inner = SQRT_2_OVER_PI * (v + COEFF * v3);
            t = tanhf(inner); b1 = 0.5f * v * (1.0f + t);

            v = b2; v3 = v * v * v;
            inner = SQRT_2_OVER_PI * (v + COEFF * v3);
            t = tanhf(inner); b2 = 0.5f * v * (1.0f + t);

            v = b3; v3 = v * v * v;
            inner = SQRT_2_OVER_PI * (v + COEFF * v3);
            t = tanhf(inner); b3 = 0.5f * v * (1.0f + t);

            o4[0] = make_float4(a0, a1, a2, a3);
            o4[1] = make_float4(b0, b1, b2, b3);
        } else {
            // Scalar tail: handles the last partial block (< 8 elements).
            // Since n = B*S*4096 and 4096 % 8 = 0, n is always a multiple of 8,
            // so this path is only taken when the grid-stride misaligns with n.
            // The compiler will still preserve it for correctness.
            for (int j = 0; j < rem; ++j) {
                float v = x[i + j];
                float v3 = v * v * v;
                float inner = SQRT_2_OVER_PI * (v + COEFF * v3);
                float t = tanhf(inner);
                out[i + j] = 0.5f * v * (1.0f + t);
            }
        }
    }
}

torch::Tensor run(torch::Tensor x) {
    auto output = torch::empty_like(x);
    size_t n = x.numel();

    constexpr int BLOCK_SIZE = 256;
    constexpr int ELEMS_PER_THREAD = 8;

    // Persistent grid-stride: size the grid to fill all 148 SMs at 100% occupancy
    // (8 blocks/SM × 256 threads = 2048 threads/SM = 64 warps/SM = max).
    // For small shapes, the grid scales down naturally to avoid launching blocks
    // that do zero work.
    int max_grid = 148 * 8;   // 148 SMs × 8 blocks/SM
    int needed = static_cast<int>(
        (n + BLOCK_SIZE * ELEMS_PER_THREAD - 1) / (BLOCK_SIZE * ELEMS_PER_THREAD)
    );
    int grid = (needed < max_grid) ? needed : max_grid;

    gelu_tanh_kernel<<<grid, BLOCK_SIZE>>>(
        x.data_ptr<float>(),
        output.data_ptr<float>(),
        n
    );

    return output;
}

